@startuml
!theme plain

class "javafx" as javafx {
  <<package>>
  class "App" as App {
    +start()
    +main()
  }
}

class "InventoryController" as InventoryController {
  +ObservableList inventoryList
}

class "Item" as Item {
  +String name
  +String serialNumber
  +BigDecimal price
  +get()
  +set()
  +toString()
}

class "FileUtil" as FileUtil {
  +File file
  +ObservableList list
  +readFromTXT()
  +readFromHTML()
  +readFromJSON()
  +readToTxt()
  +readToHTML()
  +readToJSON()
}

class "FileLoader" as FileLoader {
  +readFromTXT()
  +readFromHTML()
  +readFromJSON()
}

class "FileSaver" as FileSaver {
  +readToTxt()
  +readToHTML()
  +readToJSON()
}

javafx --|> InventoryController : composition
InventoryController -- Item : association
InventoryController -- FileUtil : association
FileUtil <|-- FileLoader : inheritance
FileUtil <|-- FileSaver : inheritance

@enduml
